CREATE TRIGGER [dbo].[BillOfProcessProcess_History]ON [dbo].[BillOfProcessProcess]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.BillOfProcessProcessId IS NOT NULL AND d.BillOfProcessProcessId IS NULL THEN 'I' 		WHEN i.BillOfProcessProcessId IS NOT NULL AND d.BillOfProcessProcessId IS NOT NULL THEN 'U' 		WHEN i.BillOfProcessProcessId IS NULL AND d.BillOfProcessProcessId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.BillOfProcessProcessId = d.BillOfProcessProcessId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_BillOfProcessProcess([BillOfProcessProcessId], [BillOfProcessId], [ProcessId], [Sequence], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfProcessProcessId], [BillOfProcessId], [ProcessId], [Sequence], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_BillOfProcessProcess([BillOfProcessProcessId], [BillOfProcessId], [ProcessId], [Sequence], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfProcessProcessId], [BillOfProcessId], [ProcessId], [Sequence], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND